/**
 * MedX search forms runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Debounced inventory search fields.
 */
const SEARCH_TOKENS = Object.freeze({
  primary: { value: "forms-search-primary", scope: "forms" },
  secondary: { value: "forms-search-secondary", scope: "forms" },
  muted: { value: "forms-search-muted", scope: "forms" },
  accent: { value: "forms-search-accent", scope: "forms" },
  surface: { value: "forms-search-surface", scope: "forms" },
});

const SEARCH_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const SEARCH_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const searchRegistry = new Map();
const SEARCH_listeners = new Set();
let SEARCH_seq = 0;

function createSearchId(prefix = "medx-forms-search") {
  SEARCH_seq += 1;
  return `${prefix}-${SEARCH_seq}`;
}

function registerSearch(config = {}) {
  const entryId = config.id ?? createSearchId();
  const preset = SEARCH_PRESETS[config.preset ?? "default"] ?? SEARCH_PRESETS.default;
  const token = SEARCH_TOKENS[config.token ?? preset.token] ?? SEARCH_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: SEARCH_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  searchRegistry.set(entryId, entry);
  notifySearchListeners("register", entry);
  return entry;
}

function updateSearch(id, patch = {}) {
  const entry = searchRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifySearchListeners("update", entry);
  return entry;
}

function resolveSearch(id) {
  const entry = searchRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listSearchEntries(filter = {}) {
  let items = Array.from(searchRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onSearchEvent(listener) {
  SEARCH_listeners.add(listener);
  return () => SEARCH_listeners.delete(listener);
}

function notifySearchListeners(type, entry) {
  for (const listener of SEARCH_listeners) {
    try {
      listener({ type, entry, registrySize: searchRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:forms:search] listener error", err.message);
    }
  }
}

function getSearchMetrics() {
  const items = listSearchEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(SEARCH_TOKENS).length,
    presets: Object.keys(SEARCH_PRESETS).length,
  };
}

async function runMedxSearch() {
  console.log("[medx:ui:forms:search] runtime initialized");
  console.log(`[medx:ui:forms:search] tokens=${Object.keys(SEARCH_TOKENS).length} presets=${Object.keys(SEARCH_PRESETS).length}`);

  const events = [];
  onSearchEvent((e) => events.push(e.type));

  const domains = Object.keys(SEARCH_SUPPLY_CHAIN);
  const presets = Object.keys(SEARCH_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerSearch({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "forms/search" },
    });
  }

  const first = listSearchEntries()[0];
  if (first) updateSearch(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getSearchMetrics();
  const resolved = first ? resolveSearch(first.id) : null;

  console.log(`[medx:ui:forms:search] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:forms:search] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:forms:search] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:forms:search] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:forms:search] bootstrap complete");
}

module.exports = runMedxSearch;
